content:
**SQL Injection** — `req.query.sort` is user-controlled and concatenated directly into the query.

**Risk:** Attacker passes `sort` values like `1; DROP TABLE invoices--` or subqueries to exfiltrate/destroy data.

**Fix:** Whitelist allowed sort columns before use.

```js
const ALLOWED = ['date','amount','status'];
if (!ALLOWED.includes(req.query.sort)) return res.status(400).end();
const sql = 'SELECT * FROM invoices ORDER BY ' + req.query.sort;
```

**Verify:**

```js
async function reconcileBatch(req, res, next) {
  try {
    const batch = await loadBatch(req);
    const rows  = await db.fetchRows(batch);
    const ruled = await applyRules(rows);
    await db.save(ruled);
    emitMetrics(ruled);
    res.sendStatus(204);
  } catch (err) {
    next(err);
  }
}
```

All db errors (and any other thrown errors) fall through to `next(err)`. No other logic changed.

```js
async function loadGatewayUser(req, res, next) {
  try {
    if (!req.session?.userId) return next();

    const user = await db.findUser(req.session.userId);
    if (!user) return next();

    await flags.load(user);
    await audit.log(user);

    req.user = user;
    next();
  } catch (err) {
    next(err);
  }
}
```
